import { useEffect } from 'react';

export default function Modal({ item, onClose }) {
  useEffect(() => {
    const fn = (e) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', fn);
    return () => document.removeEventListener('keydown', fn);
  }, [onClose]);

  if (!item) return null;

  const isShort   = item.format === 'short';
  const catLabel  = item.catLabel || (isShort ? 'Short Form · 9:16' : 'Long Form · 16:9');
  const accentCol = item.col || '#E24B4A';

  return (
    <div className="modal-bg" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className={`modal-box ${isShort ? 'portrait' : ''}`}>
        <button className="mclose" onClick={onClose}>✕</button>

        <div className={`mvideo ${isShort ? 'portrait' : ''}`}>
          {item.ytid ? (
            <iframe
              src={`https://www.youtube.com/embed/${item.ytid}?autoplay=1&rel=0&playsinline=1`}
              allow="autoplay; encrypted-media; fullscreen"
              allowFullScreen
              title={item.title || item.label}
            />
          ) : (
            <div className="mvideo-ph">
              <h3>ADD YOUR IMAGE</h3>
              <p>Replace the placeholder in data.js with an img field pointing to your file in /public</p>
            </div>
          )}
        </div>

        <div className="minfo">
          <div className="mcat" style={{ color: accentCol }}>{catLabel}</div>
          <div className="mtitle">{item.title || item.label}</div>
          <div className="mdesc">{item.desc || item.sub || ''}</div>
        </div>
      </div>
    </div>
  );
}
